import json

def trim_to_fit(title, example, max_total=800):
    total = len(title) + len(example)
    if total <= max_total:
        return example
    max_ex = max_total - len(title)
    chunk = example[:max_ex]
    for sep in ['. ', '! ', '? ']:
        pos = chunk.rfind(sep)
        if pos > max_ex - 200:
            return chunk[:pos+1]
    pos = chunk.rfind(' ')
    return chunk[:pos] + '.'

appends = {
    346: {
        0: " Вавилон возник около 2300 года до н.э. на берегах Евфрата — там где почва плодородна, вода близко, а торговые пути сходились со всей Месопотамии. Первые жители строили из глиняных кирпичей — единственного материала в безлесной долине. Город рос потому что умел принимать чужих: торговцев, мастеров, богов из других мест. Открытость была не добродетелью а необходимостью — и она стала силой.",
        1: " Кодекс Хаммурапи — 282 закона высеченных на чёрном базальтовом столбе около 1754 года до н.э. Принцип талиона: «зуб за зуб». Но закон делал различие между свободным и рабом, мужчиной и женщиной, богатым и бедным. Это не была равная справедливость — это была систематизированная иерархия. Но сам факт что наказание стало предсказуемым, а не зависело от настроения правителя — уже был революцией.",
        2: " Висячие сады Вавилона — один из семи чудес света, которое, возможно, никогда не существовало. Ни один вавилонский текст их не упоминает. Греческие источники описывают их как подарок Навуходоносора II своей жене-мидянке которая скучала по горам. Возможно сады были в Ниневии а не в Вавилоне. Но легенда выжила — потому что люди хотели верить что такое возможно: деревья растущие над городом.",
        3: " Вавилонские жрецы вели астрономические записи с VIII века до н.э. Они предсказывали затмения, рассчитывали циклы Луны и Венеры. Зодиак придумали они. Семидневная неделя с названиями по планетам — их изобретение. Астрономия и астрология не разделялись: звёзды изучали чтобы знать волю богов. Наука родилась из религии — и долго жила вместе с ней не замечая противоречия.",
        4: " История о Вавилонской башне из Книги Бытия — скорее всего описание зиккурата Этеменанки: ступенчатой пирамиды высотой 90 метров посвящённой богу Мардуку. Строительство которое евреи наблюдали во время Вавилонского плена произвело на них такое впечатление что стало метафорой человеческой гордыни. Реальная башня не была проклятием — она была религиозным центром крупнейшего города мира.",
        5: " Главный бог Вавилона Мардук победил хаос в начале времён и создал мир из тела поверженного чудовища. Это была государственная идеология: правитель — наместник бога, победа над врагами — победа порядка над хаосом. Когда Кир Персидский завоевал Вавилон — он мудро объявил себя избранником Мардука. Смена завоевателя не меняла теологию — просто бог выбирал другого человека.",
        6: " Навуходоносор II правил с 605 по 562 год до н.э. При нём Вавилон стал крупнейшим городом мира с населением до 200 000 человек. Он разрушил Иерусалим и угнал евреев в плен — это событие навсегда вошло в коллективную память через Библию. Он строил храмы, ворота, дороги. Ворота Иштар облицованные синей глазурованной плиткой с рельефными быками и драконами сохранились — и сейчас стоят в Берлинском музее.",
        7: " Вавилон изобрёл деньги в современном смысле: серебро по весу как универсальный эквивалент, долговые расписки, проценты по займам. Банкирские дома вроде Эгиби функционировали как настоящие банки: принимали вклады, выдавали кредиты, финансировали торговые экспедиции. Торговля шла от Персидского залива до Средиземного моря. Рынок требовал права, право требовало грамотности — так рождалась цивилизация.",
        8: " В 539 году до н.э. Кир II Персидский вошёл в Вавилон без боя. Жрецы Мардука открыли ворота сами — они были недовольны последним царём Набонидом который поклонялся другому богу. Кир освободил депортированные народы включая евреев. Библия называет его «помазанником Господним». Великий город не был разрушен — он просто перестал быть столицей и медленно угасал следующие несколько веков.",
        9: " Вавилон дал миру алфавитную запись чисел, концепцию нуля в позиционной системе, деление часа на 60 минут и круга на 360 градусов — всё это живёт в нас до сих пор. Слово «вавилон» в русском языке означает хаос и смешение — ирония для города который был символом порядка и закона. Первая великая цивилизация оставила следы везде кроме собственного имени которое стало синонимом путаницы.",
    },
    347: {
        0: " Кир II в 550 году до н.э. объединил персов и мидян, затем завоевал Лидию и Вавилон. Его метод был беспрецедентным: покорённым народам он позволял сохранять религию, язык, законы и местных правителей. Еврейская Библия называет его «помазанником Господним» — единственный случай когда языческий завоеватель удостоился такого титула. Кир понял то что многие завоеватели понимают слишком поздно: управлять легче чем уничтожить.",
        1: " Дарий I создал систему из 20 сатрапий — провинций с губернаторами, налогами и царскими инспекторами которых называли «глазами и ушами царя». Единая почтовая дорога длиной 2700 км от Суз до Сард позволяла гонцу доставить сообщение за неделю. Это была первая бюрократическая империя: не просто завоевание территорий, а управление ими через систему контроля, отчётности и стандартов.",
        2: " Персеполь строился с 518 года до н.э. как ритуальный центр империи. На Новый год сюда прибывали делегации всех народов с дарами. Рельефы на лестницах показывают 23 народа: каждый в своей одежде, с характерными подарками. Это была архитектурная декларация: мы — империя народов, а не уничтожитель культур. Александр сжёг Персеполь в 330 году до н.э. Греки не поняли или не захотели понять что именно сожгли.",
        3: " В 490 году до н.э. персидская армия высадилась у Марафона — и была разбита афинянами. Это поражение остановило западную экспансию Персии и родило греческий миф о победе свободных граждан над восточным деспотизмом. Реальность сложнее: Персия проиграла одну битву и отступила. Ксеркс вернулся в 480-м с огромной армией — и всё равно проиграл. Небольшая морская держава Афины остановила крупнейшую империю мира.",
        4: " Зороастризм учит что мир — арена борьбы Ахура-Мазды (добро, свет, порядок) и Ангра-Манью (зло, тьма, хаос). Человек должен выбрать сторону мыслью, словом и делом. После смерти — суд и загробная жизнь в зависимости от выбора. Эта концепция — добро против зла, загробное воздаяние, конец времён — перешла в иудаизм, христианство и ислам. Три мировые религии унаследовали зороастрийскую картину мира.",
        5: " Ксеркс сжёг Афины, получил Фермопилы ценой огромных потерь — и потерял флот при Саламине. Его поход 480-479 годов до н.э. был вершиной персидской экспансии и её концом. Геродот описал его как восточного тирана: высокомерного, мстительного, приказывающего сечь море цепями за шторм. Это греческий пропагандистский образ — но он пережил века и определил восприятие Персии как «деспотического Востока».",
        6: " Персидская «Царская дорога» соединяла Персеполь и Сузы с Сардами у Эгейского моря. Купцы везли шёлк из Китая, специи из Индии, золото из Нубии. Единая валюта — золотые дарики — облегчала торговлю. Персия создала условия для первой глобальной торговой системы: безопасные дороги, единые правовые нормы, стабильная монета. Торговля процветает когда есть порядок — Персия обеспечила и то и другое.",
        7: " Гарем существовал не только для удовольствий: это был политический институт. Жёны из покорённых народов и союзных династий цементировали союзы. Дети этих браков создавали смешанные лояльности. Но гарем был и источником нестабильности: борьба за влияние между матерями претендентов на трон порождала заговоры, яды и перевороты. Многие персидские цари были убиты придворными а не врагами на поле боя.",
        8: " Александр сжёг Персеполь в 330 году до н.э. — по официальной версии в отместку за сожжение Афин Ксерксом. По другой версии — по пьяной прихоти на вечеринке. Вероятно и то и другое. Он уничтожил главный символ империи которую только что завоевал — и тем самым лишил себя инструмента легитимности. Наследники Александра потратили десятилетия на попытки восстановить авторитет который Персия строила два века.",
        9: " Персидский язык фарси — живой наследник древнеперсидского. Зороастризм сохранился среди парсов Индии. Персидская поэзия — Хафиз, Рumi, Омар Хайям — стала мировой классикой. Идея многонациональной империи терпимой к разнообразию — персидское изобретение которое Рим и позднейшие державы воспроизводили с разным успехом. Ахеменидская Персия просуществовала 220 лет. Её культурное наследие — до сих пор.",
    },
    348: {
        0: " Октавиан Август в 27 году до н.э. сохранил все республиканские институты — сенат, консулов, народные трибуны — и добавил к ним собственную единоличную власть. Это был идеальный политический обман: диктатура в форме республики. Римляне так устали от гражданских войн что приняли мир любой ценой. Август правил 44 года. После его смерти никто уже не помнил республики — только империя казалась нормой.",
        1: " 85 000 километров мощёных дорог соединяли Рим с Британией, Египтом, Месопотамией. Дорогу строили так чтобы прослужила тысячу лет — и многие прослужили. «Все дороги ведут в Рим» — не метафора а инфраструктурный факт. Легионы перемещались со скоростью 30 км в день. Торговля текла по тем же путям. Единое транспортное пространство сделало возможным единое экономическое пространство — первое в истории Запада.",
        2: " Римский легион в 5000 человек был самой эффективной военной машиной древности. Легионеры служили 25 лет, владели латынью, умели строить лагерь за несколько часов. Они были одновременно солдатами, инженерами и колонистами. Выйдя в отставку, легионер получал землю — и оседал на завоёванной территории, распространяя латынь и римские обычаи. Армия была не только оружием завоевания — но и инструментом романизации.",
        3: " Римское право — величайшее наследие Рима. Принципы «невиновен пока не доказана вина», «право на защиту», «договор обязателен для исполнения» — всё это родилось в Риме. Кодекс Юстиниана VI века собрал тысячи лет правовой мысли. Европейские правовые системы, латиноамериканское право, международное частное право — прямые потомки римского. Когда пала империя, право пережило её и продолжает жить.",
        4: " Колизей вмещал 50 000 зрителей и работал как современный стадион: нумерованные места, навес от солнца, 80 выходов для быстрой эвакуации. «Хлеб и зрелища» — политика раздачи еды и бесплатных развлечений для городской бедноты. Это было не жестокостью а расчётом: сытый и развлечённый плебс не бунтует. Гладиаторские бои длились 400 лет — их запретил только христианский emperor Гонорий в 404 году.",
        5: " Христианство зародилось как иудейская секта в отдалённой провинции. Три века оно было вне закона — христиан казнили. Затем в 312 году Константин перед битвой увидел крест в небе и выиграл. В 380 году Феодосий сделал христианство государственной религией. Рим, гонитель, стал защитником — и церковь унаследовала имперскую структуру: папа в Риме, епископы в провинциях, латынь как язык богослужения. Империя погибла, церковная империя выжила.",
        6: " Западная Римская империя пала в 476 году — германский вождь Одоакр сверг последнего императора Ромула Августула. Это событие долго не воспринималось как катастрофа: смена варварских королей была привычной. Упадок шёл столетиями: демографический кризис, инфляция, давление варваров, разделение управления. Рим не «пал» в один день — он медленно растворился. Историки до сих пор спорят о причинах. Это сделало вопрос о гибели цивилизаций вечно актуальным.",
        7: " Константинополь основан в 330 году на месте греческого Византия — стратегически идеальная точка между Европой и Азией, Чёрным и Средиземным морями. Город с тройными стенами простоял тысячу лет после падения Рима. Он был мостом между античностью и средневековьем: хранил греческие рукописи, сохранял римское право, торговал шёлком. Когда он пал в 1453-м, учёные бежавшие на Запад привезли с собой тексты которые зажгли Ренессанс.",
        8: " Латынь умерла как разговорный язык — но превратилась в семью. Итальянский, французский, испанский, португальский, румынский — все произошли от народной латыни. Плюс латынь как язык науки, медицины, права и церкви до XVIII века. Половина английского словаря — латинского или французско-латинского происхождения. Язык мёртвой империи ежедневно звучит в устах миллиарда человек которые об этом не думают.",
        9: " Мы живём в мире форм созданных Римом: республиканское правление, разделение властей, городское планирование с сетью улиц, акведуки и канализация, публичные бани и библиотеки, концепция гражданства. Европейские университеты преподавали на латыни до XIX века. Католическая церковь до сих пор использует латынь в официальных документах. Рим — не мёртвая цивилизация. Это операционная система западного мира.",
    },
    349: {
        0: " Тэмуджин родился около 1162 года в степи без особых преимуществ: отец отравлен врагами когда ему было девять, семья брошена на голодную смерть. Он прошёл путь от раба с колодкой на шее до правителя всех монголов к 1206 году. На курултае его провозгласили Чингисханом — «всеобщим ханом». Этот путь занял 40 лет непрерывной борьбы. Не случай и не происхождение — только воля и способность превращать врагов в союзников.",
        1: " Монгольская армия не знала фиксированных формирований — она двигалась как живая система. Десятичная организация: десятки, сотни, тысячи, тумены по 10 000. Ложные отступления, охваты с флангов, психологический террор — города сдавались узнав что сопротивлявшийся сосед уничтожен. Разведка работала за месяцы до похода. Монголы не были дикарями на лошадях — они были самой профессиональной армией своего времени.",
        2: " Китай был богатейшей и технологически развитой страной мира. Монголы завоевали Северный Китай к 1234 году, Южный — к 1279-му. Хубилай-хан стал китайским императором и основал династию Юань. Завоеватели приняли китайскую бюрократию и культуру — потому что управлять Китаем иначе было невозможно. Это классический парадокс завоевания: завоеватель перенимает культуру побеждённых чтобы ею управлять.",
        3: " Батый вторгся на Русь зимой 1237-38 годов — это само по себе было военным гением: реки замёрзли и стали дорогами для конницы. Рязань, Владимир, Москва сожжены. Новгород спасло весеннее половодье. Монгольское иго длилось 240 лет и определило русскую государственность: централизованная власть, традиция выплаты даней, привычка к покорности перед силой. Историки спорят о глубине этого влияния — но отрицать его невозможно.",
        4: " Монгольская империя создала безопасный торговый маршрут от Китая до Европы под единым управлением. Купцы могли проехать 8000 километров не платя таможню на каждой границе. Марко Поло воспользовался именно этим. Вместе с шёлком и специями по Шёлковому пути шли идеи, технологии и болезни. Чума которая убила треть Европы в XIV веке пришла по тем же маршрутам по которым шла торговля.",
        5: " В 1258 году монголы уничтожили Багдад — столицу Аббасидского халифата и крупнейший город мусульманского мира. Халиф был казнён. Библиотеки сожжены или брошены в Тигр. По легенде вода реки стала чёрной от чернил рукописей. Исламский мир не оправился от этого удара несколько веков. Монгольское завоевание переломило траекторию исламской цивилизации которая до этого была мировым центром науки и философии.",
        6: " После смерти Чингисхана в 1227 году империя была разделена между сыновьями. К XIV веку она распалась на четыре улуса воевавших друг с другом. Монголы везде принимали религию и культуру покорённых: в Персии стали мусульманами, в Китае — буддистами, в России сохранили степные традиции. Адаптируясь, они растворялись. Тот кто не имеет своей культуры достаточно сильной — поглощается чужой.",
        7: " Монголы завоёвывали огнём и мечом — но потом принимали веры побеждённых. Хубилай покровительствовал буддизму. Ильханы Персии приняли ислам. Это была не слабость а прагматизм: управлять через религию легче чем против неё. Но это же стало причиной распада: разные части империи развивались в разных культурных направлениях и теряли общую идентичность.",
        8: " Монгольские завоевания XIII века убили по разным оценкам от 30 до 40 миллионов человек — около 10% населения Земли того времени. Некоторые регионы Средней Азии, Персии, Китая не восстановили численность населения 200 лет. Запустевшие поля зарастали лесом. Это была демографическая катастрофа сравнимая по масштабу со Второй мировой — только в менее населённом мире.",
        9: " Монгольские завоевания соединили Евразию в единое пространство — и запустили процессы которые изменили мир. Чума пришла в Европу по монгольским дорогам и убила треть населения — и это ускорило конец феодализма. Торговые связи Востока и Запада усилились — и привели к эпохе Великих географических открытий. Монголы хотели завоевать мир. Они его преобразили — не так как хотели.",
    },
    350: {
        0: " Осман I в конце XIII века правил крошечным племенным вождеством на границе с Византией. Он использовал слабость соседей, привлекал газиев — воинов за веру — и давал место всем кто хотел воевать. Османское государство выросло из пограничного удела в 600-летнюю империю. Это история о том как маргинальное положение на границе двух миров становится стратегическим преимуществом: ты можешь двигаться в любую сторону.",
        1: " 29 мая 1453 года Мехмед II в 21 год взял Константинополь который 1000 лет считался неприступным. Он протащил 70 кораблей по суше через холм — чтобы обойти цепь перекрывавшую Золотой Рог. Последний византийский император Константин XI погиб в бою. Мехмед въехал в Святую Софию на коне и превратил её в мечеть. Это был конец Средневековья для Запада — и начало османского века для Востока.",
        2: " Сулейман I правил с 1520 по 1566 год — дольше любого османского султана. При нём империя достигла максимума: от Алжира до Месопотамии, от Венгрии до Аравии. Он вёл переписку с Франциском I Французским — союз против Габсбургов. В Европе его называли Великолепным, в империи — Законодателем. Он лично написал кодекс законов который действовал три века. Поэт, ювелир, государственный администратор — редкое сочетание.",
        3: " Система миллетов позволяла христианам, евреям и другим немусульманам жить по собственным законам под руководством своих религиозных лидеров. Они платили особый налог, не служили в армии и имели ограниченные права. Но их не преследовали за веру. По меркам Европы где шли религиозные войны — это была поразительная терпимость. Когда евреев изгоняли из Испании в 1492-м, Османская империя их приняла.",
        4: " Янычары создавались через девширме: христианских мальчиков забирали у семей, обращали в ислам и воспитывали как элитных воинов абсолютно преданных султану. Без семей, без собственности, без иной лояльности. Это была абсолютная верность купленная отрывом от корней. Но к XVII веку янычары превратились в политическую силу: они возводили и свергали султанов, не давали проводить реформы. Инструмент власти стал её ограничением.",
        5: " К XVIII веку Османская империя теряла войны с Россией и Австрией, отдавала территории, подписывала унизительные договоры. «Больной человек Европы» — термин который приписывают Николаю I. Реформы XIX века — Танзимат — пытались модернизировать армию, администрацию, образование. Но реформы проводились под давлением извне и сопротивлением внутри. Когда реформа не успевает за распадом — она только затягивает агонию.",
        6: " В 1915-1916 годах османское правительство организовало депортацию и массовое убийство армян. Погибло от 600 000 до 1,5 миллиона человек — оценки расходятся. Турция до сих пор официально отрицает геноцид. Это одно из первых массовых уничтожений этнической группы в XX веке — и его непризнание остаётся открытой раной в международных отношениях. История которую государство отказывается признавать — не исчезает. Она просто продолжает давить.",
        7: " Первая мировая война стала для Османской империи последней. Союз с Германией оказался проигрышным. Севрский договор 1920 года разделил анатолийские земли между Грецией, Арменией, Францией, Британией. Это спровоцировало турецкую войну за независимость под командованием Мустафы Кемаля. Лозаннский договор 1923-го признал Турецкую республику. Империя которая строилась 600 лет была разобрана за несколько лет.",
        8: " Ататюрк провёл радикальную секуляризацию: упразднил халифат, закрыл религиозные суды, заменил арабское письмо латинским алфавитом, запретил традиционную одежду, дал женщинам право голоса раньше чем Франция. Он строил национальное государство из имперских обломков. Метод был авторитарным, темп — шоковым. Но альтернативой был распад. Иногда хирургия больнее болезни — и всё равно необходима.",
        9: " Османское наследие живёт в государственных границах Ближнего Востока проведённых британцами и французами после 1918-го по османским административным делениям без учёта этнического состава. Отсюда — конфликты которые продолжаются. Турецкий язык содержит тысячи арабских и персидских слов. Архитектура от Каира до Белграда несёт следы османских мечетей и хаммамов. Шесть веков не исчезают — они становятся слоем почвы под ногами.",
    },
    351: {
        0: " 1492 год: Колумб открыл Америку, Реконкиста завершила 800-летнюю войну с маврами, евреев изгнали из Испании. Всё в один год. Испания вышла из средневековой войны с огромной армией, религиозным единством, золотом отнятым у мавров — и не знала что с этим делать. Америка стала ответом. Энергия столетней войны обернулась энергией завоевания нового мира — с той же жестокостью и тем же религиозным пылом.",
        1: " Эрнан Кортес завоевал Ацтекскую империю с 600 солдатами против армии в сотни тысяч. Франсиско Писарро взял Инкскую империю с 170 людьми. Это не было военным гением — это было стечением обстоятельств: оспа убила большую часть населения до прихода испанцев, местные союзники ненавидели ацтекских и инкских завоевателей, стальные доспехи и лошади давали психологическое преимущество. Но конкистадоры не знали что победят — и всё равно шли.",
        2: " Потоси в современной Боливии — гора из серебра открытая в 1545 году. К 1600-му это был крупнейший город Западного полушария с населением 160 000 человек. Миллионы тонн серебра ушли в Испанию — и оттуда в Азию за шёлком и специями. Парадокс: богатство разорило Испанию. Приток серебра вызвал инфляцию, убил местное производство, создал зависимость от колониального импорта. «Ресурсное проклятие» — не современное изобретение.",
        3: " В 1580 году Филипп II присоединил Португалию — и на несколько десятилетий стал хозяином всех европейских колоний в Азии, Африке и Америке. Испанская империя в момент пика занимала 13 миллионов квадратных километров. Оборонять такие территории было невозможно. Армада патрулировала моря, но пираты Дрейка грабили флоты безнаказанно. Перерасширение — смерть империй: сила рассеивается по периметру и не успевает ни на что.",
        4: " В 1588 году Филипп II послал «Непобедимую Армаду» — 130 кораблей — против Англии Елизаветы. Шторм в Ла-Манше и английская тактика брандеров уничтожили флот. Испания потеряла морское господство. Это не был мгновенный крах — Испания оставалась великой державой ещё столетие. Но психологический перелом произошёл: «непобедимых» победили. После Армады на морях появились голландцы, англичане, французы.",
        5: " Инквизиция в испанских колониях сжигала не еретиков а синкретические культы: местные жители смешивали христианство со старыми богами. Испания несла «цивилизацию» через крещение, принудительный труд в энкомьендах, уничтожение местных письменных систем. Бартоломе де лас Касас — монах который это видел — написал «Краткое донесение о разрушении Индий»: первый в истории документ защиты прав коренных народов. Голос протеста звучал с самого начала.",
        6: " Испанская Америка создала новую цивилизацию: метисы, креолы, синкретическая культура смешавшая европейское, индейское и африканское. Испанский барокко расцвёл в Мексике и Перу богаче чем в самой Испании. Гибридные культуры часто продуктивнее чистых: они не отвергают ни один из источников а синтезируют всё. Латинская Америка — живое доказательство.",
        7: " К 1825 году все материковые колонии Испании стали независимыми республиками. Симон Боливар мечтал о конфедерации — «Соединённые штаты Латинской Америки». Не вышло: местные элиты предпочли отдельные государства. Испания потеряла империю которую строила 300 лет — но оставила язык, религию, правовую систему и культуру которые живут в 20 государствах и объединяют 500 миллионов человек.",
        8: " Испанский язык — второй в мире по числу носителей как родного: 485 миллионов человек. Первый по географическому распространению: 20 стран на четырёх континентах. Это наследие не завоевания а колонизации которая длилась 300 лет и создала общество где испанский стал языком власти, церкви, образования и в конце концов — дома. Язык колонизатора стал языком потомков колонизированных. Так работает культурная ассимиляция.",
        9: " Испания переосмыслила свою имперскую историю позже других: франкистская диктатура поддерживала миф о «цивилизаторской миссии». Только с 1990-х в испанских школах стали преподавать колониализм критически. Статуи Колумба сносят в латиноамериканских городах. Но потомки конкистадоров и потомки ацтеков говорят на одном языке, слушают одну музыку и едят одну кухню. История сложнее чем жертвы и палачи.",
    },
    352: {
        0: " Александр родился в 356 году до н.э. в македонском дворе: отец Филипп II — военный гений, учитель Аристотель — лучший ум эпохи. Два года Аристотель учил его философии, риторике, медицине, науке. Александр брал в походы «Илиаду» с пометками учителя и считал Ахилла своим образцом. Он был первым в истории лидером получившим систематическое философское образование — и это отличало его от всех предшественников.",
        1: " В 334 году до н.э. Александр переправился через Геллеспонт с 37 000 солдат. К 323 году его империя простиралась от Греции до современного Пакистана. Он не проиграл ни одного сражения. Гавгамелы, Исс, осада Тира — каждая битва решала задачу которую все считали невозможной. Его армия прошла 32 000 километров за 11 лет. Это был не просто военный поход — это было самое дерзкое предприятие в истории Античности.",
        2: " В Индии у реки Гифасис в 326 году армия отказалась идти дальше. Солдаты плакали — но не двигались. Александр три дня не выходил из шатра. Потом развернулся. Это единственный раз когда «нет» остановило его. Он умер в Вавилоне в 323 году — возможно от тифа, возможно отравленный, возможно от последствий многолетнего пьянства и ран. Ему было 32. Он так и не нашёл края мира который хотел завоевать.",
        3: " Александр основал более 20 городов названных Александрией. Крупнейшая — в Египте — стала на три века центром эллинистического мира. Он не просто завоёвывал — он строил инфраструктуру эллинизма: города по греческому образцу с агорой, гимназием, театром. Эти города стали узлами сети распространявшей греческий язык и культуру от Египта до Индии. Завоевание как урбанизация — редкий подход в истории.",
        4: " Эллинизм — это когда греческая культура смешалась с персидской, египетской, вавилонской. Александр сам носил персидскую одежду, требовал проскинезы — земного поклона как перед персидским царём. Македонцы были в ярости. Но он видел что управлять огромной многонациональной империей через одну культуру невозможно. Синтез культур породил александрийскую науку, стоическую философию, Септуагинту — греческий перевод Библии.",
        5: " Гефестион — ближайший друг Александра с детства. Когда он умер в 324 году до н.э. Александр не выходил из комнаты два дня, приказал распять врача, срезал гривы лошадям в трауре. Историки спорят о природе их отношений. Но ясно одно: Александр потерял единственного человека которому доверял полностью — и после этого сам умер через несколько месяцев. Иногда одна потеря определяет конец.",
        6: " В Вавилоне в июне 323 года Александр заболел после пира. Десять дней лихорадки — и умер. Когда его спросили кому оставляет империю — сказал «сильнейшему». Или «кратисту» — лучшему. Никакого завещания не было. Его тело мумифицировали и отправили в Александрию Египетскую где Птолемей построил ему гробницу ставшую местом паломничества. Гробница была утеряна в Средневековье. Её ищут до сих пор.",
        7: " Диадохи — «наследники» — 40 лет воевали за обломки империи. К 280 году до н.э. возникли три главных государства: Птолемеи в Египте, Селевкиды в Азии, Антигониды в Македонии. Они воевали друг с другом, но все говорили по-гречески и строили греческие города. Александр не создал единой наследующей власти — зато создал культурное пространство которое пережило политический распад.",
        8: " Александрийская библиотека основанная Птолемеем I собирала все книги мира. Корабли прибывавшие в Александрию обязаны были сдавать рукописи для копирования — оригиналы оставались, копии возвращались. В пике хранилось 700 000 свитков. Это была первая попытка собрать всё знание человечества в одном месте. Она сгорела — не в одном пожаре а постепенно через несколько столетий. Знание более хрупко чем кажется.",
        9: " Александр Великий — один из немногих людей история которых превратилась в миф ещё при жизни. Он считал себя богом — или хотел чтобы так считали другие. После смерти его образ был присвоен всеми: Рим видел в нём образец, Персия — своего царя, средневековые рыцари — героя, Наполеон носил его портрет. Каждая эпоха создаёт своего Александра. Это и есть величие — когда человек становится зеркалом для чужих амбиций.",
    },
    353: {
        0: " Около 1325 года ацтеки (мешики) были изгоями — их не принимали в развитые города долины Мехико. Они нашли орла сидящего на кактусе с змеёй в клюве — знак богов — на острове в болотистом озере. Там они основали Теночтитлан. За 200 лет из болотных беженцев они стали хозяевами крупнейшей империи Мезоамерики. Непрестижное начало не определяет конец — оно только задаёт направление усилий.",
        1: " Ацтеки создали Тройственный союз с Тескоко и Тлакопаном в 1428 году. Быстрые военные походы, дань с покорённых городов, разветвлённая торговая сеть. К 1500 году империя включала 5-6 миллионов подданных на территории современной Мексики. Ацтеки не уничтожали побеждённых — они брали дань и пленников для жертвоприношений. Это создавало постоянное недовольство которым воспользовались испанцы.",
        2: " Теночтитлан к 1519 году был крупнейшим городом западного полушария: 200-300 тысяч жителей. Город на острове соединён с берегом тремя дамбами. Акведуки, рынки, зоопарк, ботанический сад. Испанцы входя в него сравнивали с Венецией и не верили своим глазам. Берналь Диас написал: «Всё что мы видели было таким чудесным что не знали — реальность это или сон».",
        3: " Ацтекские жертвоприношения — самое шокирующее и самое используемое в пропаганде их наследие. Масштаб был огромным: тысячи человек в год. Но это была не жестокость ради жестокости — это была космология: боги дали кровь чтобы создать мир, люди должны возвращать кровь чтобы солнце продолжало восходить. Без жертвы — конец света. Это не оправдание. Но это объяснение которого обычно не хватает.",
        4: " Монтесума II встретил Кортеса с почестями в 1519 году. Версия о том что он принял его за бога Кецалькоатля — скорее всего испанский миф созданный позже. Реальность прозаичнее: Монтесума взял время чтобы понять что за люди пришли. Кортес захватил его в заложники прямо во дворце. Монтесума умер при невыясненных обстоятельствах — испанцы говорят что его убили собственные подданные. Историки сомневаются.",
        5: " В июне 1520-го ацтеки восстали и выгнали испанцев из Теночтитлана. Это называется «Ночь печали»: Кортес потерял половину армии, всё золото и чуть не погиб сам. Он отступил — но не ушёл. Год ушёл на сбор союзников из народов ненавидевших ацтеков, строительство флота на озере и осаду города. В августе 1521-го Теночтитлан пал. Поражение которое не стало концом — а стало началом другой истории.",
        6: " К 1520 году оспа убила возможно половину населения Мексики ещё до прямого столкновения с испанцами. Монтесума умер от оспы. Её принесли сами испанцы — без злого умысла, но с катастрофическим результатом. Биологическая катастрофа сделала военное завоевание возможным. Это самый страшный пример того как контакт цивилизаций которые развивались в изоляции может быть смертоносен для одной из них.",
        7: " Ацтеки создали иероглифическую письменность, сложный календарь (365-дневный солнечный и 260-дневный ритуальный), медицину, астрономию, архитектуру. Кодексы — книги из коры — хранили историю, законы, религию. Испанцы сожгли большинство из них как языческие. Епископ Диего де Ланда уничтожил тысячи книг майя. Потом написал книгу об их культуре — по рассказам выживших. Уничтожитель стал нечаянным хранителем.",
        8: " Первый епископ Мексики Хуан де Сумаррага сжёг тысячи рукописей ацтеков в 1520-30-х. До нас дошло около 15 подлинных кодексов. Это была не только культурная потеря — это было уничтожение языка на котором говорила 2000-летняя традиция. Когда письменность уничтожена — история передаётся устно и трансформируется. Мы не знаем ацтеков такими какими они знали себя сами.",
        9: " Современные мексиканцы в большинстве своём метисы — потомки и испанцев и коренных народов. Официальная идеология Мексики с 1920-х — «индихенизм»: гордость индейским наследием как основой национальной идентичности. Статуя Куаутемока — последнего ацтекского правителя — стоит на главном проспекте Мехико. Имя Кортеса нигде в городе не увековечено. Нация выбирает кого помнить как предка.",
    },
    354: {
        0: " Пётр I в 1697-98 годах инкогнито ехал в Западную Европу в составе «Великого посольства». Учился корабельному делу в Голландии, работал руками на верфи, набирал специалистов. Вернувшись, он начал реформы которые буквально изменили внешность страны: запретил бороды, велел носить европейскую одежду, перенёс столицу на болото у Балтики. Модернизация через насилие — это не только советское изобретение.",
        1: " Северная война со Швецией длилась 21 год (1700-1721). В первом сражении при Нарве Пётр потерял армию — и вернулся с новой. Полтава в 1709-м стала переломом: шведская армия разбита, Карл XII бежал. Россия получила выход к Балтике и статус европейской державы. Цена: сотни тысяч погибших, строительство Петербурга на костях, налоги которые доводили до восстаний. Пётр строил Россию по образцу Европы — насилием и кровью.",
        2: " Екатерина II правила 1762-1796 — 34 года, дольше любого другого монарха XVIII века. Она переписывалась с Вольтером и Дидро, основала Эрмитаж, написала «Наказ» — инструкцию по реформе законов. И она подавила восстание Пугачёва, расширила крепостное право, разделила Польшу. Просвещённый абсолютизм: идеи Просвещения для элиты, крепостной труд как основа экономики. Противоречие которое никого не смущало.",
        3: " Наполеон вошёл в Москву в сентябре 1812-го — и нашёл пустой горящий город. Жители ушли. Запасов нет. Зимовать в пепелище невозможно. Французская армия начала отступление в октябре и потеряла 90% состава — от холода, голода, партизан. Это была не столько военная победа России сколько логистическая катастрофа Франции. Урок: самое большое государство — само по себе оружие. Пространство и зима работают без приказа.",
        4: " К 1861 году когда Александр II освободил крестьян — крепостных было около 23 миллионов человек, треть населения. Они не могли уйти с земли, продавались вместе с имением, подвергались телесным наказаниям. «Освобождение» дало свободу без земли и с выкупными платежами которые крестьяне платили до 1907 года. Реформа которая не меняет экономической сути — это реформа для истории а не для людей.",
        5: " Николай II отрёкся в марте 1917-го. Он не понимал что происходит — его дневники в дни революции полны записей о прогулках и погоде. Последний Романов был добрым семьянином и катастрофическим правителем. Он верил в самодержавие когда страна требовала конституции, вёл войну когда армия разлагалась, слушал Распутина когда нужны были реформаторы. Личная добродетель не компенсирует политическую слепоту.",
        6: " XIX век — золотой век русской литературы: Пушкин, Гоголь, Тургенев, Достоевский, Толстой, Чехов — за одно столетие. Чайковский, Мусоргский, Римский-Корсаков в музыке. Репин, Суриков в живописи. Страна с крепостным правом и цензурой создала мировую культуру первого ряда. Это не парадокс — давление и ограничения создают напряжение которое иногда выражается в искусстве. Свобода не обязательное условие гения.",
        7: " Россия расширялась на восток через Сибирь с конца XVI века. Казаки Ермака разбили Сибирское ханство в 1582-м. К 1639-му русские вышли к Тихому океану. Это самое быстрое сухопутное расширение в истории: 10 000 километров за 60 лет. Не было заморской экспедиции — только казаки в меховых шубах двигавшиеся по рекам. Они несли государство за собой а не перед собой.",
        8: " Февраль 1917: царь отрёкся, Временное правительство взяло власть. Октябрь 1917: большевики захватили власть у Временного правительства. Это не было неизбежным: Ленин приехал в апреле в запломбированном вагоне через Германию которой выгоден был хаос в России. Большевики были маленькой партией которая знала чего хочет — в то время как все остальные не знали. Революции выигрывают не самые многочисленные а самые решительные.",
        9: " Российская империя оставила крупнейшее государство в мире: СССР и потом Россия унаследовали территорию. Русский язык стал языком межнационального общения на пространстве от Балтики до Тихого океана. Православная культура, имперская архитектура, литературная традиция — всё это живёт. Но главное наследие — вопрос о соотношении государства и личности, реформы и традиции, Европы и Азии — остаётся открытым и сегодня.",
    },
}

desc_fixes = {
    346: "Вавилон — первая великая цивилизация мира: законы Хаммурапи, висячие сады и астрономия которая дала нам зодиак и семидневную неделю.",
    348: "Рим подарил миру право, латынь, христианство и саму идею цивилизации — и его наследие живёт в каждом европейском государстве до сих пор.",
    349: "Кочевники завоевали полмира за 60 лет — и создали первую глобальную торговую сеть от Китая до Европы ценой 40 миллионов жизней.",
    353: "За 200 лет из болотных изгоев в хозяев Мексики. Теночтитлан был крупнейшим городом мира — пока не пришли испанцы с оспой.",
}

with open('/root/books/webapp/books.json', 'r', encoding='utf-8') as f:
    books = json.load(f)

target = set(appends.keys())
for b in books:
    bid = b['id']
    if bid not in target: continue
    if bid in desc_fixes:
        b['description'] = desc_fixes[bid]
    for i, t in enumerate(b['thoughts']):
        if i in appends[bid]:
            t['example'] += appends[bid][i]
        t['example'] = trim_to_fit(t['title'], t['example'])

with open('/root/books/webapp/books.json', 'w', encoding='utf-8') as f:
    json.dump(books, f, ensure_ascii=False, separators=(',', ':'))

print("=== VERIFY batch 1 ===")
issues = []
for b in books:
    if b['id'] not in target: continue
    d = len(b['description'])
    if not(125<=d<=150): issues.append(f"ID {b['id']} DESC BAD({d}): {b['description'][:60]}")
    for i, t in enumerate(b['thoughts']):
        total = len(t['title']) + len(t['example'])
        s = 'OK' if 700<=total<=800 else ('SHORT' if total<700 else 'LONG')
        if s != 'OK': issues.append(f"ID {b['id']} t{i} {s}={total}: {t['title'][:40]}")
if issues:
    print("ISSUES:"); [print(" ", x) for x in issues]
else:
    print("All OK!")
